BEGIN SET NOCOUNT ON;
-- Parse patient IDs into table DECLARE @PatientIdTable TABLE (PatientId UNIQUEIDENTIFIER);
INSERT INTO @PatientIdTable (PatientId) SELECT CAST(value AS UNIQUEIDENTIFIER) FROM STRING_SPLIT(@PatientIds, ',') WHERE value <> '';
-- Get all allergies for these patients SELECT a.PatientId, a.AllergyId, a.AllergenName, a.AllergenType, a.Reaction, a.Severity, a.OnsetDate FROM pt.Allergies a INNER JOIN @PatientIdTable p ON a.PatientId = p.PatientId ORDER BY a.PatientId, a.Severity DESC; END

CREATE PROCEDURE pt.usp_GetAllergiesBulk
    @PatientIds NVARCHAR(MAX) -- Comma-separated GUIDs
AS

BEGIN SET NOCOUNT ON;
-- Patient basic info SELECT p.PatientId, p.FirstName + ' ' + p.LastName AS PatientName, p.Email, p.PhoneNumber FROM pt.Patients p WHERE p.PatientId = @PatientId AND p.IsDeleted = 0;
-- Primary insurance SELECT TOP 1 i.InsuranceId, i.PayerName, i.PlanName, i.MemberId, i.EffectiveDate, i.ExpirationDate FROM pt.Insurances i WHERE i.PatientId = @PatientId AND i.IsActive = 1 AND i.Priority = 1 ORDER BY i.EffectiveDate DESC;
-- Counts SELECT (SELECT COUNT(*) FROM pt.FamilyRelations WHERE PatientId = @PatientId) AS FamilyMemberCount, (SELECT COUNT(*) FROM pt.Allergies WHERE PatientId = @PatientId) AS AllergyCount, (SELECT COUNT(*) FROM pt.Medications WHERE PatientId = @PatientId AND IsActive = 1) AS MedicationCount, (SELECT COUNT(*) FROM pt.Documents WHERE PatientId = @PatientId) AS DocumentCount; END

BEGIN
    SET NOCOUNT ON;

    DECLARE @HasBasicInfo BIT = 0;
    DECLARE @HasContactInfo BIT = 0;
    DECLARE @HasEmergencyContact BIT = 0;
    DECLARE @HasInsurance BIT = 0;
    DECLARE @HasAllergies BIT = 0;
    DECLARE @IsComplete BIT = 0;

    -- Check if patient exists
    IF NOT EXISTS (SELECT 1 FROM pt.Patients WHERE PatientId = @PatientId AND IsDeleted = 0)
    BEGIN
        -- Return error result
        SELECT NULL AS PatientId, 0 AS IsComplete, 'Patient not found' AS ErrorMessage;
        RETURN;
    END

    -- Check basic info
    SELECT @HasBasicInfo = CASE 
        WHEN FirstName IS NOT NULL AND FirstName <> ''
         AND LastName IS NOT NULL AND LastName <> ''
         AND Email IS NOT NULL AND Email <> ''
        THEN 1 ELSE 0 END
    FROM pt.Patients
    WHERE PatientId = @PatientId;

    -- Check contact info
    SELECT @HasContactInfo = CASE 
        WHEN PhoneNumber IS NOT NULL AND PhoneNumber <> ''
         AND AddressLine1 IS NOT NULL AND AddressLine1 <> ''
        THEN 1 ELSE 0 END
    FROM pt.Patients
    WHERE PatientId = @PatientId;

    -- Check emergency contact
    SELECT @HasEmergencyContact = CASE 
        WHEN EmergencyContactName IS NOT NULL AND EmergencyContactName <> ''
         AND EmergencyContactPhone IS NOT NULL AND EmergencyContactPhone <> ''
        THEN 1 ELSE 0 END
    FROM pt.Patients
    WHERE PatientId = @PatientId;

    -- Check insurance (optimized with index)
    IF EXISTS (SELECT 1 FROM pt.Insurances WHERE PatientId = @PatientId AND IsActive = 1)
        SET @HasInsurance = 1;

    -- Check allergies (optimized with index)
    IF EXISTS (SELECT 1 FROM pt.Allergies WHERE PatientId = @PatientId)
        SET @HasAllergies = 1;

    -- Calculate overall completeness
    SET @IsComplete = CASE 
        WHEN @HasBasicInfo = 1 AND @HasContactInfo = 1 
         AND @HasEmergencyContact = 1 AND @HasInsurance = 1 
         AND @HasAllergies = 1
        THEN 1 ELSE 0 END;

    -- Return result
    SELECT 
        @PatientId AS PatientId,
        @IsComplete AS IsComplete,
        @HasBasicInfo AS HasBasicInfo,
        @HasContactInfo AS HasContactInfo,
        @HasEmergencyContact AS HasEmergencyContact,
        @HasInsurance AS HasInsurance,
        @HasAllergies AS HasAllergies;
END

BEGIN
    SET NOCOUNT ON;
    BEGIN TRY
        BEGIN TRANSACTION;

        -- Parse JSON
        DECLARE @PatientId UNIQUEIDENTIFIER;
        DECLARE @FirstName NVARCHAR(100);
        DECLARE @LastName NVARCHAR(100);
        DECLARE @Email NVARCHAR(100);

        SELECT 
            @PatientId = JSON_VALUE(@PatientData, '$.patient.id'),
            @FirstName = JSON_VALUE(@PatientData, '$.patient.firstName'),
            @LastName = JSON_VALUE(@PatientData, '$.patient.lastName'),
            @Email = JSON_VALUE(@PatientData, '$.patient.email');

        -- Check if new or update
        IF @PatientId IS NULL OR @PatientId = '00000000-0000-0000-0000-000000000000'
        BEGIN
            SET @PatientId = NEWID();

            -- Insert new patient (simplified - full implementation would parse all JSON fields)
            INSERT INTO pt.Patients (
                PatientId, FirstName, LastName, Email, 
                CreatedAt, CreatedBy, IsActive, IsDeleted
            )
            VALUES (
                @PatientId, @FirstName, @LastName, @Email,
                GETUTCDATE(), @CreatedBy, 1, 0
            );
        END
        ELSE
        BEGIN
            -- Update existing patient
            UPDATE pt.Patients
            SET 
                FirstName = @FirstName,
                LastName = @LastName,
                Email = @Email,
                UpdatedAt = GETUTCDATE(),
                UpdatedBy = @CreatedBy
            WHERE PatientId = @PatientId;
        END

        -- Log audit
        INSERT INTO pt.AuditLogs (
            AuditLogId, PatientId, EventType, EntityType, EntityId,
            EventTimestamp, ActorId, ActorName, Action, Success, PhiAccessed
        )
        VALUES (
            NEWID(), @PatientId, 'Update', 'Patient', @PatientId,
            GETUTCDATE(), @CreatedBy, @CreatedBy, 'Comprehensive intake completed', 1, 1
        );

        COMMIT TRANSACTION;

        -- Return patient ID
        SELECT @PatientId AS PatientId, 'Success' AS Status;
        RETURN 0;

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0
            ROLLBACK TRANSACTION;

        -- Return error
        SELECT 
            NULL AS PatientId, 
            'Error' AS Status,
            ERROR_MESSAGE() AS ErrorMessage;
        RETURN -1;
    END CATCH
END

CREATE PROCEDURE pt.usp_SavePatientIntake
    @PatientData NVARCHAR(MAX), -- JSON format
    @CreatedBy NVARCHAR(100)
AS

BEGIN SET NOCOUNT ON;
DECLARE @Offset INT = (@PageNumber - 1) * @PageSize;
-- Get total count DECLARE @TotalCount INT;
SELECT @TotalCount = COUNT(*) FROM pt.Patients p WHERE p.IsDeleted = 0 AND (@SearchTerm IS NULL OR p.FirstName LIKE '%' + @SearchTerm + '%' OR p.LastName LIKE '%' + @SearchTerm + '%') AND (@Email IS NULL OR p.Email = @Email) AND (@PhoneNumber IS NULL OR p.PhoneNumber = @PhoneNumber) AND (@DateOfBirth IS NULL OR CAST(p.DateOfBirth AS DATE) = @DateOfBirth);
-- Get paginated results SELECT p.PatientId, p.FirstName, p.MiddleName, p.LastName, p.DateOfBirth, p.Gender, p.Email, p.PhoneNumber, p.City, p.State, @TotalCount AS TotalCount, @PageNumber AS CurrentPage, @PageSize AS PageSize FROM pt.Patients p WHERE p.IsDeleted = 0 AND (@SearchTerm IS NULL OR p.FirstName LIKE '%' + @SearchTerm + '%' OR p.LastName LIKE '%' + @SearchTerm + '%') AND (@Email IS NULL OR p.Email = @Email) AND (@PhoneNumber IS NULL OR p.PhoneNumber = @PhoneNumber) AND (@DateOfBirth IS NULL OR CAST(p.DateOfBirth AS DATE) = @DateOfBirth) ORDER BY p.LastName, p.FirstName OFFSET @Offset ROWS FETCH NEXT @PageSize ROWS ONLY; END

CREATE PROCEDURE pt.usp_SearchPatients
    @SearchTerm NVARCHAR(100) = NULL,
    @Email NVARCHAR(100) = NULL,
    @PhoneNumber NVARCHAR(25) = NULL,
    @DateOfBirth DATE = NULL,
    @PageNumber INT = 1,
    @PageSize INT = 20
AS

BEGIN SET NOCOUNT ON;
-- Check if patient exists IF NOT EXISTS (SELECT 1 FROM pt.Patients WHERE PatientId = @PatientId AND IsDeleted = 0) BEGIN RAISERROR('Patient not found', 16, 1); RETURN -1; END
-- Update only provided fields UPDATE pt.Patients SET FirstName = ISNULL(@FirstName, FirstName), MiddleName = CASE WHEN @MiddleName IS NOT NULL THEN @MiddleName ELSE MiddleName END, LastName = ISNULL(@LastName, LastName), Suffix = CASE WHEN @Suffix IS NOT NULL THEN @Suffix ELSE Suffix END, DateOfBirth = ISNULL(@DateOfBirth, DateOfBirth), Gender = ISNULL(@Gender, Gender), MaritalStatus = CASE WHEN @MaritalStatus IS NOT NULL THEN @MaritalStatus ELSE MaritalStatus END, Race = CASE WHEN @Race IS NOT NULL THEN @Race ELSE Race END, Ethnicity = CASE WHEN @Ethnicity IS NOT NULL THEN @Ethnicity ELSE Ethnicity END, PreferredLanguage = CASE WHEN @PreferredLanguage IS NOT NULL THEN @PreferredLanguage ELSE PreferredLanguage END, UpdatedAt = GETUTCDATE(), UpdatedBy = @UpdatedBy WHERE PatientId = @PatientId;
-- Log audit INSERT INTO pt.AuditLogs ( AuditLogId, PatientId, EventType, EntityType, EntityId, EventTimestamp, ActorId, ActorName, Action, Success, PhiAccessed ) VALUES ( NEWID(), @PatientId, 'Update', 'Patient', @PatientId, GETUTCDATE(), @UpdatedBy, @UpdatedBy, 'Personal information updated', 1, 1 );
RETURN 0; END

